require("UI.UI_RpgMask")function UIMgr:UI_RpgMask_Create(a)local b;if GameMgr.Inst.prefer_language=='chs'or GameMgr.Inst.prefer_language=='chs_t'then b=LuaTools.LoadPrefab('prefab/ui_output/UI_RpgMask',a)else b=LuaTools.LoadPrefab('prefab/ui_output/UI_RpgMask',a)end;if not b then return nil end;b.gameObject:SetActive(false)local c=UI_RpgMask:Create(b)c.right=c.transform:Find("right")c.left=c.transform:Find("left")c:OnCreate()return c end